mapper.select:
select 
  from batch.system_parameter
 where tenant_id = #{tenantId}
   and param_key = #{paramKey}
 limit 1

mapper.insert:
insert into batch.system_parameter (
    tenant_id, param_key, param_value, description, created_by, updated_by
) values (
    #{tenantId}, #{paramKey}, #{paramValue}, #{description}, #{operator}, #{operator}
)
on conflict (tenant_id, param_key) do update
    set param_value = #{paramValue},
        description = #{description},
        updated_by  = #{operator},
        updated_at  = current_timestamp

mapper.delete:
delete from batch.system_parameter
 where tenant_id = #{tenantId}
   and param_key = #{paramKey}
